import * as React from "react"

interface TabsProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  defaultValue: string;
  onValueChange?: (value: string) => void;
}

interface TabsContentProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  value: string;
  hidden?: boolean;
}

interface TabsListProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
}

interface TabsTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  value: string;
}

export function Tabs({ children, defaultValue, onValueChange, ...props }: TabsProps) {
  const [value, setValue] = React.useState(defaultValue);

  const handleValueChange = (newValue: string) => {
    setValue(newValue);
    onValueChange?.(newValue);
  };

  const childrenWithProps = React.Children.map(children, (child) => {
    if (!React.isValidElement(child)) return child;

    const childElement = child as React.ReactElement;

    if (childElement.type === TabsContent) {
      const contentChild = childElement as React.ReactElement<TabsContentProps>;
      return React.cloneElement(contentChild, {
        hidden: contentChild.props.value !== value
      });
    }

    if (childElement.type === TabsList) {
      const listChild = childElement as React.ReactElement<TabsListProps>;
      return React.cloneElement(listChild, {
        'aria-label': 'tabs',
        children: React.Children.map(listChild.props.children, (tab) => {
          if (!React.isValidElement(tab)) return tab;
          if (tab.type === TabsTrigger) {
            const triggerChild = tab as React.ReactElement<TabsTriggerProps>;
            return React.cloneElement(triggerChild, {
              onClick: () => handleValueChange(triggerChild.props.value),
              'aria-selected': triggerChild.props.value === value,
              className: `${triggerChild.props.className || ''} ${triggerChild.props.value === value ? 'active' : ''}`
            });
          }
          return tab;
        })
      });
    }

    return child;
  });

  return <div {...props}>{childrenWithProps}</div>;
}

export function TabsContent({ children, value, hidden, ...props }: TabsContentProps) {
  if (hidden) return null;
  return <div {...props}>{children}</div>;
}

export function TabsList({ children, ...props }: TabsListProps) {
  return <div role="tablist" {...props}>{children}</div>;
}

export function TabsTrigger({ children, value, ...props }: TabsTriggerProps) {
  return (
    <button role="tab" type="button" {...props}>
      {children}
    </button>
  );
}
